#include<bits/stdc++.h>
using namespace std;
const int N=3e6+10;
int t[N][150],idx,cnt[N];
void add(string s){
	int p=0;
	for(int i=0;i<s.size();i++){
		if(!t[p][s[i]])t[p][s[i]]=++idx;
		p=t[p][s[i]];
	}
	cnt[p]++;
}
int find(string s){
	int p=0,sum=0;
	for(int i=0;i<s.size();i++){
		if(!t[p][s[i]])return sum;
		p=t[p][s[i]];
		sum+=cnt[p];
	}
	return sum;
}
int main()
{
	int n,q;
	cin>>n>>q;
	for(int i=0;i<n;i++){
		string s;
		cin>>s;
		add(s);
	}
	for(int i=0;i<q;i++){
		string s;
		cin>>s;
		cout<<find(s)<<endl;
	}
}
